repl("Finding the spreadsheet link", "const idsFromPerf1 = await page.evaluate(() => {
  const urls = performance.getEntriesByType('resource').map(e => e.name).concat([location.href]);
  const matches = [];
  for (const u of urls) {
    const m = u.match(/\/spreadsheets\/d\/([a-zA-Z0-9-_]+)/);
    if (m) matches.push({id:m[1], url:u});
  }
  return [...new Map(matches.map(x=>[x.id,x])).values()];
});
console.log(JSON.stringify(idsFromPerf1, null, 2).slice(0,4000));")

